// Accept lesson_id from parent workflow (W_Master) via Execute Workflow Trigger.
// Manual Trigger has no payload — lesson_id stays null and Code nodes downstream
// skip the lesson_id filter (operate on ALL segments — backward-compatible legacy behavior).
const incoming = $input.first()?.json || {};
const lesson_id = incoming.lesson_id || null;
return [{ json: { lesson_id } }];

// Batches tone analysis into chunks of TONE_BATCH so a long lesson (100+ segments)
// doesn't overflow a single Claude call or exceed max_tokens.
const TONE_BATCH = 40;
const lesson_id = $('Get Params').first().json.lesson_id;
let segments = $input.all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .map(i => ({ segment_id: i.json.segment_id, en_text: i.json.en_text }));
if (lesson_id) segments = segments.filter(s => s.segment_id.startsWith(lesson_id + '_'));
if (segments.length === 0) throw new Error('No segments to analyze' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));

const sysPrompt = 'Classify each wellness/meditation segment. Return ONLY a JSON object where each key is segment_id and value has: segment_type (narrative|instruction|movement), movement_keywords (comma-sep if movement, else empty string), key_concepts (2-4 comma-sep themes). No markdown, no preamble. Every input segment_id MUST appear in the output.';

const batches = [];
for (let i = 0; i < segments.length; i += TONE_BATCH) {
  batches.push(segments.slice(i, i + TONE_BATCH));
}

return batches.map(batch => ({
  json: {
    model: 'claude-sonnet-4-5',
    max_tokens: 4000,
    system: sysPrompt,
    messages: [{ role: 'user', content: 'Segments:\n\n' + JSON.stringify(batch, null, 2) }],
  },
}));

// Merges tone analysis from one or more batched Claude responses — emits per-segment items.
const merged = {};
for (const item of $input.all()) {
  try {
    let raw = item.json.content?.[0]?.text?.trim() || '{}';
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) { console.error('Parse Tone Map: no JSON in batch response'); continue; }
    const batchMap = JSON.parse(match[0]);
    Object.assign(merged, batchMap);
  } catch (e) {
    console.error('Parse Tone Map: parse failed for one batch:', e.message);
  }
}
if (Object.keys(merged).length === 0) throw new Error('Tone analysis returned empty results across all batches');
return Object.entries(merged).map(([segment_id, meta]) => ({
  json: { segment_id, segment_type: meta.segment_type || 'narrative', movement_keywords: meta.movement_keywords || '', key_concepts: meta.key_concepts || '' }
}));

// Batched translation: groups segments into batches of BATCH_SIZE and emits one Claude request per batch.
// This dramatically reduces Anthropic API request count (31 → 4 for a typical lesson) and stays under
// the default tier's output-tokens-per-minute ceiling (8K), which 1-segment-per-call hits at ~14 segments.
const lesson_id = $('Get Params').first().json.lesson_id;
const configItems = $('Read Config').all();
const configMap = {};
configItems.forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const tov = configMap['tone_of_voice'] || '';

const toneItems = $('Parse Tone Map').all();
const toneMap = {};
toneItems.forEach(i => { if (i.json.segment_id) toneMap[i.json.segment_id] = i.json; });

const BATCH_SIZE = 8;

const segments = $('Read Pending Segments').all()
  .filter(i => i.json.segment_id && i.json.en_text)
  .filter(i => !lesson_id || i.json.segment_id.startsWith(lesson_id + '_'));

const sysParts = [
  'You are a translator for meditation/wellness audio scripts.',
  'INPUT: a JSON object mapping segment_id → { text, type?, key_concepts? }. Each "text" value is the English text to translate. Even when the text is very short or sounds conversational ("I am here.", "Yes.", "I am."), IT IS STILL TEXT TO TRANSLATE — never respond conversationally and never skip a segment.',
  'OUTPUT: a single JSON object mapping every input segment_id to an object with EXACTLY these 7 keys: de, es, fr, pl, pt, it, tr. Each value = translation in that language.',
  'EVERY input segment_id MUST appear in the output. If you skip any, the run fails downstream.',
  'Informal address in all languages (du/tu/ty/sen, never formal).',
  "Preserve '...' and '—' as pause timing cues.",
  'NO preamble, NO markdown, NO commentary, NO ```json fences. Output ONLY the JSON object, starting with { and ending with }.',
];
if (tov) sysParts.push('\n=== TONE OF VOICE ===\n' + tov + '\n=== END TONE OF VOICE ===');
const systemBlocks = [
  { type: 'text', text: sysParts.join('\n'), cache_control: { type: 'ephemeral' } },
];

const batches = [];
for (let i = 0; i < segments.length; i += BATCH_SIZE) {
  batches.push(segments.slice(i, i + BATCH_SIZE));
}

return batches.map((batch, bIdx) => {
  const userMap = {};
  const batchInfo = [];
  for (const s of batch) {
    const sid = s.json.segment_id;
    const enText = (s.json.en_text || '').replace(/"/g, "'");
    const tone = toneMap[sid] || {};
    userMap[sid] = { text: enText };
    if (tone.segment_type) userMap[sid].type = tone.segment_type;
    if (tone.key_concepts) userMap[sid].key_concepts = tone.key_concepts;
    batchInfo.push({ segment_id: sid, en_text: s.json.en_text, en_duration_sec: s.json.en_duration_sec });
  }
  return {
    json: {
      batch_index: bIdx,
      batch_size: batch.length,
      batch_segments: batchInfo,
      claude_body: {
        model: 'claude-sonnet-4-5',
        max_tokens: 8000,
        system: systemBlocks,
        messages: [{ role: 'user', content: JSON.stringify(userMap, null, 2) }],
      },
    },
  };
});

// Parses batched Claude response → emits one item per segment.
// Each batch's Claude reply is a JSON object: { segment_id: { de, es, fr, pl, pt, it, tr }, ... }.
const REQUIRED_LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];
const preparedItems = $('Prepare and Expand').all();
const claudeItems = $input.all();
const results = [];

for (let i = 0; i < claudeItems.length; i++) {
  const claudeResp = claudeItems[i].json;
  const batchSegments = preparedItems[i]?.json?.batch_segments || [];
  const batchIdx = preparedItems[i]?.json?.batch_index ?? i;

  let batchTranslations = {};
  try {
    let text = claudeResp.content?.[0]?.text?.trim() || '{}';
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = text.match(/\{[\s\S]*\}/);
    if (match) batchTranslations = JSON.parse(match[0]);
  } catch(e) {
    console.error(`Extract Translations: parse error on batch ${batchIdx}: ${e.message}`);
  }

  for (const seg of batchSegments) {
    const translations = batchTranslations[seg.segment_id] || {};
    const filled = REQUIRED_LANGS.filter(l => translations[l] && translations[l].trim());
    if (filled.length === 0) {
      console.error(`Extract Translations: skip ${seg.segment_id} — empty/missing in batch ${batchIdx}. Sheet row preserved.`);
      continue;
    }
    if (filled.length < REQUIRED_LANGS.length) {
      const missing = REQUIRED_LANGS.filter(l => !filled.includes(l));
      console.warn(`Extract Translations: ${seg.segment_id} missing langs: ${missing.join(',')}`);
    }
    results.push({ json: {
      segment_id:      seg.segment_id,
      en_text:         seg.en_text || '',
      en_duration_sec: seg.en_duration_sec || 0,
      de_text: translations.de || '',
      es_text: translations.es || '',
      fr_text: translations.fr || '',
      pl_text: translations.pl || '',
      pt_text: translations.pt || '',
      it_text: translations.it || '',
      tr_text: translations.tr || '',
    }});
  }
}
return results;

// Verify Translations — QA pass on Sonnet's initial output.
// Batches segments (8 at a time), sends to Claude with anti-pattern rules.
// Applies corrections when Claude returns a different value; pass-through otherwise.
// QA_SYSTEM is sized ≥1024 tokens so cache_control: ephemeral activates on Sonnet 4.5.
const QA_BATCH_SIZE = 8;
const LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const apiKey = configMap.anthropic_api_key || '';
if (!apiKey) throw new Error('anthropic_api_key missing from config sheet');

const QA_SYSTEM = `You are a quality reviewer for meditation/wellness translations.

INPUT: a JSON object mapping segment_id → { en, de, es, fr, pl, pt, it, tr }. Each segment has the English source plus 7 translations.

YOUR JOB: detect and fix THREE classes of issues that degrade meditative/affirmative meaning. The English texts are SELF-ACCEPTANCE AFFIRMATIONS in a meditation context — never bureaucratic statements, marketing copy, or clinical instructions.

=== CLASS 1: LITERAL-DICTIONARY MISTRANSLATIONS (false friends) ===
These literal renderings carry the wrong register or meaning. Replace if found:
- DE: "gültig" for "valid" (means "valid ticket/document"). Use "Ich bin wertvoll." or "Ich bin richtig, so wie ich bin."
- FR: "suffisant" for "enough" when about a person (means "arrogant, conceited"). Use "Je suis assez." or "Je me suffis."
- FR: "valide" for "valid" when about a person (means "able-bodied"). Use "Je suis légitime." or "J'ai ma place."
- TR: "geçerli/geçerliyim" for "valid" (means "valid as a rule/password"). Use "Değerliyim." or "Ben yeterliyim."
- PL: bare "Jestem dość." for "I am enough" (ungrammatical). Use "Jestem wystarczający." or "Jestem dość dobry."
- ES: "válido" for "valid" about a person reads clinical/legal. Prefer warmer "Yo valgo." or "Tengo valor."
- PT: "válido" for "valid" about a person reads clinical/legal. Prefer "Eu tenho valor." or "Eu importo."
- IT: "valido" for "valid" about a person reads clinical. Prefer "Ho valore." or "Sono prezioso."
- ES/PT/IT: "suficiente"/"sufficiente" applied to a person is grammatical but reads flat for affirmations. When slot allows, prefer self-acceptance phrasing like "Yo soy quien soy." / "Eu sou quem sou." / "Io sono chi sono."
- ANY obvious typos: double letters where they shouldn't be, missing or wrong diacritics on common words.

=== CLASS 2: FORMALITY DRIFT (must stay informal singular) ===
All translations MUST use informal singular address. Replace any formal-creep:
- DE: must use "du/dich/dein", NEVER "Sie/Ihnen/Ihr" or capitalized formal forms.
- ES: must be Castilian "tú/te/tu", NEVER "usted/le/su"; NEVER Latin American "vos/ustedes".
- FR: must use "tu/te/ton/ta/tes", NEVER "vous/votre/vos".
- IT: must use "tu/ti/tuo/tua/tuoi/tue", NEVER capitalized formal "Lei/La/Suo/Le".
- PL: must use direct "ty"-form verbs (e.g., "jesteś", "czujesz"), NEVER "Pan/Pani/Państwo" or third-person formality.
- PT: must be European Portuguese "tu/te/teu/tua" with EU conjugation ("tu fazes", "tu sentes"), NEVER Brazilian "você/seu/sua" or BR verb forms ("você faz", "você sente").
- TR: must use "sen/seni/senin", NEVER "siz/sizi/sizin" or capitalized formal forms.

=== CLASS 3: TONE-OF-VOICE VIOLATIONS ===
Spirio's voice is the warm, knowing friend — not a guru, coach, or marketer. Replace or soften:
- Marketing/transformation vocab: "transformación/transformation/Transformation", "alpha", "vibration/vibración", "manifest/manifester/manifestar", "energy field" — strip or rephrase to plain sensation.
- Promise/guarantee tone: "you will feel amazing" → soften to "you might notice" / "puedes notar" / "tu peux remarquer" / "vielleicht spürst du" / etc.
- Bare imperative filler: "Just relax", "Be present", "Calm down" without sensation grounding — replace with sensation-grounded language ("let your shoulders drop", "notice the weight of your hands").
- Clinical/medical register: "diagnóstico", "intervención terapéutica", over-formal Latinisms in ES/PT/IT — soften to everyday vocabulary.
- Word-for-word anglicism: a translation that copies English syntax verbatim and reads stilted in the target language. Rephrase to native rhythm without losing meaning.
- Urgency words: "immediately", "ya mismo", "tout de suite", "sofort" — these break meditative pacing.

=== HARD CONSTRAINTS (do not violate even when correcting) ===
- LENGTH: keep corrections within ±25% of original character count (TTS timing budget).
- NEGATIONS: preserve "no"/"not"/"never"/"without" exactly as in source.
- CONTRASTS: preserve "A, not B" / "A but B" / "A instead of B" patterns exactly.
- NUMBERS, PROPER NOUNS, NAMED TECHNIQUES: never alter.
- PAUSE MARKERS: preserve "..." and "—" exactly.
- For clean translations that violate none of the three classes, RETURN THEM UNCHANGED. Do not edit for style alone.

=== OUTPUT FORMAT ===
JSON object mapping segment_id → { de, es, fr, pl, pt, it, tr } with same 7 langs. No "en" in output. No commentary. No markdown fences. Only the JSON.`;

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function callQA(body) {
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.anthropic.com/v1/messages',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body, json: true,
      });
      return resp.content?.[0]?.text?.trim() || '';
    } catch (e) {
      if (attempt === MAX_TRIES - 1) { console.error('Verify Translations QA failed after retries:', e.message); return ''; }
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

const items = $input.all();
const batches = [];
for (let i = 0; i < items.length; i += QA_BATCH_SIZE) batches.push(items.slice(i, i + QA_BATCH_SIZE));

const corrections = {};
for (const batch of batches) {
  const userMap = {};
  for (const it of batch) {
    const j = it.json;
    userMap[j.segment_id] = {
      en: j.en_text || '',
      de: j.de_text || '', es: j.es_text || '', fr: j.fr_text || '',
      pl: j.pl_text || '', pt: j.pt_text || '', it: j.it_text || '', tr: j.tr_text || '',
    };
  }
  const body = {
    model: 'claude-sonnet-4-5',
    max_tokens: 8000,
    system: [{ type: 'text', text: QA_SYSTEM, cache_control: { type: 'ephemeral' } }],
    messages: [{ role: 'user', content: JSON.stringify(userMap, null, 2) }],
  };
  const raw = await callQA.call(this, body);
  try {
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) Object.assign(corrections, JSON.parse(match[0]));
  } catch (e) { console.error('Verify Translations parse error:', e.message); }
}

// Apply corrections: if QA returned a value for a lang, use it; else keep original.
return items.map(it => {
  const sid = it.json.segment_id;
  const corr = corrections[sid] || {};
  const out = { ...it.json };
  for (const lang of LANGS) {
    const key = `${lang}_text`;
    if (corr[lang] && corr[lang].trim()) out[key] = corr[lang].trim();
  }
  return { json: out };
});

const LANG_CPS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };
const LANGS = ['de', 'es', 'fr', 'pl', 'pt', 'it', 'tr'];
const BUDGET_FACTOR = 1.05;
const MAX_ATTEMPTS = 3;
const MIN_RETAIN = 0.60;  // never accept shortening below 60% of input
const ANTHROPIC_URL = 'https://api.anthropic.com/v1/messages';

const configItems = $('Read Config').all();
const configMap = {};
configItems.forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const apiKey = configMap['anthropic_api_key'] || '';
if (!apiKey) throw new Error('anthropic_api_key missing from config sheet');

// Per-language CPS — defaults tuned against real ElevenLabs output; overridable via
// config keys cps_estimate_de, cps_estimate_es, …, cps_estimate_tr. Computed below.
const CPS_DEFAULTS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };

const SYSTEM_PROMPT = `You are a localization editor for meditation/wellness audio. Your job is to shorten a translated text so it fits within a strict time budget for audio dubbing.

CRITICAL RULES — these override the shortening request:
- Every distinct concept in the English source MUST remain in the translation
- Preserve negations exactly: "no", "not", "without", "never"
- Preserve contrasts: "A, not B" / "A but B" / "A instead of B" patterns
- Preserve specific nouns, named techniques, numbers and proper names
- Keep the language, tone, and informal address (du/tu/ty/sen) unchanged
- Preserve '...' and '—' as pause timing cues
- Do NOT translate or switch languages — edit only the given translation
- Only remove genuinely redundant filler words (e.g., "really", "very", "just", "actually")
- Return ONLY the shortened text. No explanation, no quotes, no preamble.
- DO NOT include character counts, "(N characters)", or any meta-commentary.
- DO NOT include reasoning words ("Wait", "Let me", "Actually", "Note:", "Hmm").
- DO NOT use markdown formatting (**, __, backticks).
- DO NOT include multiple drafts — pick ONE and output only it.
- DO NOT include blank lines.`;

const ATTEMPT_PROMPTS = [
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation slightly (~5-15%) to fit within ${budget}s (currently ~${est}s).
Remove only filler words and minor redundancies. Preserve sentence structure and all key concepts.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation more (~15-25%) to fit within ${budget}s (currently ~${est}s).
Rephrase for compactness, but every concept from the English source must remain.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
  (lang, budget, est, en, trans, minChars) =>
    `Shorten this ${lang} translation as much as possible to fit within ${budget}s (currently ~${est}s).
Preserve every distinct concept, negation, contrast, and proper noun from the English. Cut only filler and stylistic flourishes.
Minimum allowed length: ${minChars} characters.

Original English (preserve all concepts): ${en}
Current translation: ${trans}`,
];


// Strip Claude meta-commentary.
// Meditation translations are always single-line, so cut at the FIRST newline —
// anything after is meta-commentary like "(Already at N characters; cannot shorten further)"
// which Claude (esp. Sonnet) sometimes appends on a single newline (not \n\n).
function sanitizeClaudeOutput(rawText) {
  if (!rawText) return '';
  let t = rawText.trim();
  const nlIdx = t.indexOf('\n');
  if (nlIdx >= 0) t = t.substring(0, nlIdx).trim();
  t = t.replace(/^[\*_]+|[\*_]+$/g, '').trim();
  t = t.replace(/^["'`]+|["'`]+$/g, '').trim();
  // Strip trailing parenthesized meta even on same line ("text (12 chars)")
  t = t.replace(/\s*\([^)]*(character|char|cannot|already|maximally|minimal)[^)]*\)\s*$/i, '').trim();
  return t;
}

function estimateDuration(text, lang) {
  return text.length / (LANG_CPS[lang] || 15);
}

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function callClaude(userContent) {
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: ANTHROPIC_URL,
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body: { model: 'claude-sonnet-4-5', max_tokens: 500, system: SYSTEM_PROMPT, messages: [{ role: 'user', content: userContent }] },
        json: true,
      });
      return sanitizeClaudeOutput(resp.content?.[0]?.text || '');
    } catch (e) {
      const isLast = attempt === MAX_TRIES - 1;
      if (isLast) { console.error('Adapt callClaude failed after retries:', e.message); return ''; }
      // Exponential backoff: 2s, 4s, 8s.
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

const results = [];
for (const item of $input.all()) {
  const { segment_id, en_text, en_duration_sec } = item.json;
  const budget = parseFloat(en_duration_sec) || 0;
  const out = { segment_id, en_text, en_duration_sec: budget };
  let maxAttempts = 0;

  for (const lang of LANGS) {
    let text = item.json[`${lang}_text`] || '';
    let attempts = 0;
    if (text && budget) {
      for (let a = 0; a < MAX_ATTEMPTS; a++) {
        const est = estimateDuration(text, lang);
        if (est <= budget * BUDGET_FACTOR) break;
        const minChars = Math.floor(text.length * MIN_RETAIN);
        const shortened = await callClaude.call(this, ATTEMPT_PROMPTS[a](lang, budget.toFixed(1), est.toFixed(1), en_text, text, minChars));
        // Length floor: reject Claude output that went below 60% of input length
        if (shortened && shortened.length >= minChars) {
          text = shortened;
        }
        attempts = a + 1;
      }
    }
    out[`${lang}_text`] = text;
    out[`${lang}_adaptation_attempts`] = attempts;
    if (attempts > maxAttempts) maxAttempts = attempts;
  }
  out.adaptation_attempts = maxAttempts;
  results.push({ json: out });
}
return results;
